- `/Users/anotonio.silva/antonio/lol/src/components/snippet_manager/snippet_manager_view.tsx`
- `/Users/anotonio.silva/antonio/lol/src/components/file_search/file_search_view.tsx`

---

### 3. Search & Filtering Pattern

**Pattern**: Two-tier filtering:
1. **Dropdown filter** for categories/types (discrete values like "Code", "General")
2. **Text search** via SearchBar using fuzzy matching

**Implementation**:
```typescript
const filtered = useMemo(() => {
  let items = entries;

  // Apply category/type filter
  if (filterValue !== 'all') {
    items = items.filter(e => e.category === filterValue);
  }

  // Apply fuzzy search
  if (query) {
    items = items.filter(e => 
      fuzzyMatch(query, e.name) || 
      fuzzyMatch(query, e.keyword) ||
      fuzzyMatch(query, e.content)
    );
  }

  return items;
}, [entries, query, filterValue]);
```

**SearchDropdown sections**:
```typescript
const FILTER_SECTIONS: SearchDropdownSection[] = [
  {
    options: [{ label: 'All', value: 'all' }],
  },
  {
    title: 'Category',
    options: SNIPPET_CATEGORIES.map(c => ({
      label: c.label,
      value: c.value,
    })),
  },
];
```

---

### 4. Actions & Keyboard Shortcuts Pattern

**Pattern**: Three-layer action system:

1. **Keyboard shortcuts** for common actions (registered via `useKeyboardShortcut`)
2. **ActionPanel** with quick actions displayed at bottom
3. **ActionPanel dropdown** with detailed actions accessed via ⌘K

**Implementation**:
```typescript
// Register keyboard shortcuts
useKeyboardShortcut(
  { key: 'k', meta: true },
  toggleActions,
  { enabled: subView === 'list' }
);

useKeyboardShortcut(
  { key: 'c', meta: true },
  handleCopy,
  { enabled: subView === 'list' }
);

// ActionPanel with dropdown
<ActionPanel
  contextLabel="Snippets"
  actions={[
    { label: 'Insert', shortcut: <Kbd keys={['↵']} /> },
    { label: 'Actions', shortcut: <Kbd keys={['⌘', 'K']} />, onClick: toggleActions }
  ]}
  dropdownOpen={actionsOpen}
  dropdownSections={dropdownSections}
  onDropdownClose={closeActions}
/>
```

**Dropdown sections structure**:
```typescript
const dropdownSections: DropdownSection[] = [
  {
    title: 'Actions',
    actions: [
      { label: 'Insert', shortcut: <Kbd keys={['↵']} />, onClick: handleInsert },
      { label: 'Edit', shortcut: <Kbd keys={['⌘', 'E']} />, onClick: handleEdit },
    ],
  },
  {
    title: 'Danger Zone',
    actions: [
      { label: 'Delete', shortcut: <Kbd keys={['⌘', '⌫']} />, onClick: handleDelete },
    ],
  },
];
```

---

### 5. Persistence Pattern

**Pattern**: LocalStorage-based persistence with type guards

```typescript
interface StoredSnippet {
  id: string;
  name: string;
  keyword: string;
  content: string;
  category: string;
  tags: { text: string; color?: string }[];
  createdAt: string; // ISO string for JSON
}

function loadSnippets(): SnippetEntry[] {
  const stored = storageGet(SNIPPETS_KEY, isStoredSnippetArray);
  if (stored) return deserializeEntries(stored);
  return MOCK_SNIPPET_ENTRIES;
}

function saveSnippets(entries: SnippetEntry[]) {
  storageSet(SNIPPETS_KEY, serializeEntries(entries));
}

// Deserialization with validation
function deserializeEntries(stored: StoredSnippet[]): SnippetEntry[] {
  return stored.map(s => ({
    ...s,
    category: isSnippetCategory(s.category) ? s.category : 'general',
    createdAt: new Date(s.createdAt),
  }));
}
```

---

### 6. Command Registration Pattern

**Pattern**: Centralized registry with declarative command definitions

```typescript
registerCommand({
  id: 'snippets',
  name: 'Search Snippets',
  subtitle: 'Search Snippets',
  icon: SnippetsIcon(),
  keywords: ['snippet', 'text', 'expand', 'template'],
  section: 'Suggestions',
  accessories: [
    { date: new Date(Date.now() - 1000 * 60 * 60 * 3) },
    { text: 'Raycast' }
  ],
  detail: {
    markdown: `# Search Snippets\n...`,
    metadata: [
      { type: 'label', title: 'Application', text: 'Raycast' },
      { type: 'label', title: 'Type', text: 'Command' },
    ],
  },
  component: SnippetManagerView,
  fullView: true,
});
```

**Key properties**:
- `id`: Unique identifier
- `name`: Display name in command palette
- `icon`: ReactNode (rendered SVG)
- `keywords`: Search matching terms
- `section`: Grouping ("Suggestions", "Commands", "Applications")
- `component`: Full view component if `fullView: true`
- `detail`: Rich detail panel with markdown + metadata
- `aliases`: Additional search terms

**File**: `/Users/anotonio.silva/antonio/lol/src/registry/commands.ts`

---

### 7. List Rendering Pattern

**Pattern**: Global index tracking for grouped sections

```typescript
return (
  <List itemCount={totalItemCount} onActiveIndexChange={handleActiveIndexChange}>
    {(() => {
      let globalIndex = 0; // Tracks position across all sections
      const sections: ReactNode[] = [];

      for (const group of groupedByCategory) {
        sections.push(
          <ListSection key={group.title} title={group.title}>
            {group.items.map(entry => {
              const idx = globalIndex++;
              return (
                <ListItem
                  key={entry.id}
                  index={idx}
                  icon={...}
                  title={entry.name}
                  subtitle={...}
                  accessories={[...]}
                  query={query || undefined}
                />
              );
            })}
          </ListSection>
        );
      }

      return sections;
    })()}
  </List>
);
```

---

### 8. Shared Types Pattern

**Pattern**: Core interface definitions in `src/types.ts`

```typescript
export interface ListItemData {
  id: string;
  title: string;
  subtitle?: string;
  icon?: ReactNode;
  accessories?: ListItemAccessoryData[];
  detail?: ListItemDetailData;
}

export interface ListItemAccessoryData {
  text?: string;
  icon?: ReactNode;
  date?: Date;
  tag?: { text: string; color?: TagColor };
  tooltip?: string;
}

export type ListItemMetadataEntry =
  | { type: 'label'; title: string; text?: string }
  | { type: 'link'; title: string; text: string; target: string }
  | { type: 'tag-list'; title: string; tags: {...}[] }
  | { type: 'separator' };
```

**File**: `/Users/anotonio.silva/antonio/lol/src/types.ts`

---

### 9. Hooks Pattern

**Pattern**: Custom hooks for cross-cutting concerns

Used throughout views:
- `useNavigation()`: Breadcrumb management
- `useKeyboardShortcut()`: Keyboard event handling
- `useAlert()`: Confirmation dialogs
- `useHUD()`: Toast notifications

**Example**:
```typescript
const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();

confirmAlert({
  title: `Delete "${entryName}"?`,
  message: 'This snippet will be permanently deleted.',
  primaryAction: { label: 'Delete', style: 'destructive', onAction: () => {...} },
  dismissAction: { label: 'Cancel', style: 'cancel', onAction: () => {} }
});
```

---

### 10. Icon Pattern

**Pattern**: Inline SVG definitions or imported icon components

```typescript
function SnippetHUDIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
      <rect x="3" y="2" width="10" height="12" rx="1.5" stroke="currentColor" strokeWidth="1.5" />
      {/* SVG content */}
    </svg>
  );
}

// Or imported from data files
import { getFileIcon } from '../../data/file_search_data';
const icon = getFileIcon(entry.fileType);
```

---

## Import Organization

**Pattern**: Barrel imports at component level, specific imports from utilities

```typescript
// Components (barrel imports)
import { SearchBar } from '../search_bar/search_bar';
import { List, ListItem, ListSection } from '../list';
import { ActionPanel } from '../action_panel/action_panel';

// Hooks (specific)
import { useAlert } from '../../hooks/use_alert';
import { useHUD } from '../../hooks/use_hud';
import { useKeyboardShortcut } from '../../hooks/use_keyboard_shortcut';

// Utilities (specific)
import { fuzzyMatch } from '../../utils/fuzzy_search';
import { formatRelativeDate } from '../../utils/format_date';
import { storageGet, storageSet } from '../../utils/storage';

// Data (specific)
import { MOCK_SNIPPET_ENTRIES, SNIPPET_CATEGORIES } from '../../data/snippet_data';
```

---

## Summary

The Raycast UI clone uses a **modular, composable architecture** with:
1. **Separation of concerns**: Data, views, hooks, utilities are isolated
2. **Declarative command registration**: Commands are registered once and reused
3. **State management**: Controlled components with `useMemo` for derived state
4. **Persistence**: LocalStorage with type-safe serialization/deserialization
5. **Accessibility**: Keyboard shortcuts, breadcrumbs, ARIA attributes
6. **Reusable patterns**: List grouping, filtering, actions, icons follow consistent conventions

