181→  }, []);
182→
183→  const handleActiveIndexChange = useCallback((index: number) => {
184→    setSelectedIndex(index);
185→    setActionsOpen(false);
186→  }, []);
187→
188→  const handleOpen = useCallback(() => {
189→    if (!selectedEntry) return;
190→    setActionsOpen(false);
191→    showHUD({
192→      icon: <OpenInBrowserHUDIcon />,
193→      title: `Opened ${selectedEntry.name}`,
194→    });
195→  }, [
196→    selectedEntry,
197→    showHUD,
198→  ]);
199→
200→  const handleShowInFinder = useCallback(() => {
201→    if (!selectedEntry) return;
202→    setActionsOpen(false);
203→    showHUD({
204→      icon: <OpenInBrowserHUDIcon />,
205→      title: 'Revealed in Finder',
206→    });
207→  }, [
208→    selectedEntry,
209→    showHUD,
210→  ]);
211→
212→  const handleCopyPath = useCallback(() => {
213→    if (!selectedEntry) return;
214→    setActionsOpen(false);
215→    performCopy(selectedEntry.path, showHUD, {
216→      hudTitle: 'Path Copied',
217→    });
218→  }, [
219→    selectedEntry,
220→    showHUD,
221→  ]);
222→
223→  const handleDelete = useCallback(() => {
224→    if (!selectedEntry) return;
225→    const entryId = selectedEntry.id;
