233→          <circle cx="16" cy="16" r="14" fill="currentColor" opacity="0.15" />
234→          <path
235→            d="M12 13V22M16 13V22M20 13V22M10 10H22M13 10V9C13 8.45 13.45 8 14 8H18C18.55 8 19 8.45 19 9V10"
236→            stroke="currentColor"
237→            strokeWidth="1.5"
238→            strokeLinecap="round"
239→            strokeLinejoin="round"
240→          />
241→        </svg>
242→      ),
243→      primaryAction: {
244→        label: 'Move to Trash',
245→        style: 'destructive',
246→        onAction: () => {
247→          setEntries(prev => prev.filter(e => e.id !== entryId));
248→          showHUD({
249→            icon: <CopyHUDIcon />,
250→            title: `Moved "${entryName}" to Trash`,
251→          });
252→        },
253→      },
254→      dismissAction: {
255→        label: 'Cancel',
256→        style: 'cancel',
257→        onAction: () => {},
258→      },
259→    });
260→  }, [
261→    selectedEntry,
262→    confirmAlert,
263→    showHUD,
264→  ]);
265→
266→  const handleAction = useCallback(() => {
267→    handleOpen();
268→  }, [handleOpen]);
269→
270→  const toggleActions = useCallback(() => {
271→    setActionsOpen(prev => !prev);
272→  }, []);
273→
