interface StoredSnippet {
  id: string;
  name: string;
  keyword: string;
  content: string;
  category: string;
  tags: {
    text: string;
    color?: string;
  }[];
  createdAt: string;
}

function isStoredTag(value: unknown): value is {
  text: string;
  color?: string;
} {
  if (!isRecord(value)) return false;
  if (typeof value.text !== 'string') return false;
  if ('color' in value && typeof value.color !== 'string') {
    return false;
  }
  return true;
}

function isStoredSnippetArray(value: unknown): value is StoredSnippet[] {
  if (!Array.isArray(value)) return false;
  return value.every(
    v =>
      isRecord(v) &&
      typeof v.id === 'string' &&
      typeof v.name === 'string' &&
      typeof v.keyword === 'string' &&
      typeof v.content === 'string' &&
      typeof v.category === 'string' &&
      typeof v.createdAt === 'string' &&
      Array.isArray(v.tags) &&
      v.tags.every(isStoredTag),
  );
}

function serializeEntries(entries: SnippetEntry[]): StoredSnippet[] {
  return entries.map(e => ({
    ...e,
    createdAt: e.createdAt.toISOString(),
  }));
}

const TAG_COLOR_NAMES = new Set<string>(Object.keys(TAG_COLOR_HEX));

function isTagColor(value: string): value is TagColor {
  return TAG_COLOR_NAMES.has(value);
}

function deserializeEntries(stored: StoredSnippet[]): SnippetEntry[] {
  return stored.map(s => {
    const parsed = new Date(s.createdAt);
    const createdAt = Number.isNaN(parsed.getTime()) ? new Date() : parsed;
    return {
      ...s,
      category: isSnippetCategory(s.category) ? s.category : 'general',
      tags: s.tags.map(t => ({
        text: t.text,
        color: t.color && isTagColor(t.color) ? t.color : undefined,
      })),
      createdAt,
    };
  });
}

function loadSnippets(): SnippetEntry[] {
  const stored = storageGet(SNIPPETS_KEY, isStoredSnippetArray);
  if (stored) return deserializeEntries(stored);
  return MOCK_SNIPPET_ENTRIES;
}

function saveSnippets(entries: SnippetEntry[]) {
  storageSet(SNIPPETS_KEY, serializeEntries(entries));
}

const FILTER_SECTIONS: SearchDropdownSection[] = [
  {
    options: [
      {
        label: 'All',
        value: 'all',
      },
    ],
  },
  {
    title: 'Category',
    options: SNIPPET_CATEGORIES.map(c => ({
      label: c.label,
      value: c.value,
    })),
  },
];

interface SnippetFormState {
  name: string;
  keyword: string;
  snippet: string;
  category: SnippetCategory;
  tags: string[];
}

const INITIAL_SNIPPET_FORM: SnippetFormState = {
  name: '',
  keyword: '',
  snippet: '',
  category: 'general',
  tags: [],
};

const FORM_TAG_OPTIONS = SNIPPET_TAGS.map(t => ({
  label: t.label,
  value: t.value,
}));

const FORM_CATEGORY_OPTIONS = SNIPPET_CATEGORIES.map(c => ({
  label: c.label,
  value: c.value,
}));

interface EditSnippetViewProps {
  snippet?: SnippetEntry;
  onSubmit: (form: SnippetFormState) => void;
}

function EditSnippetView({ snippet, onSubmit }: EditSnippetViewProps) {
  const [form, setForm] = useState<SnippetFormState>(() => {
    if (snippet) {
      return {
        name: snippet.name,
        keyword: snippet.keyword,
        snippet: snippet.content,
        category: snippet.category,
        tags: snippet.tags.map(t => t.text.toLowerCase()),
      };
    }
    return INITIAL_SNIPPET_FORM;
  });
  const [errors, setErrors] = useState<
    Partial<Record<keyof SnippetFormState, string>>
  >({});

  const handleSubmit = useCallback(() => {
    const newErrors: Partial<Record<keyof SnippetFormState, string>> = {};
    if (!form.name.trim()) {
      newErrors.name = 'Name is required';
    }
    if (!form.snippet.trim()) {
      newErrors.snippet = 'Snippet content is required';
    }
    setErrors(newErrors);
    if (Object.keys(newErrors).length > 0) return;
    onSubmit(form);
  }, [
    form,
    onSubmit,
  ]);

  useKeyboardShortcut(
    {
      key: 'Enter',
      meta: true,
    },
    handleSubmit,
  );

  return (
    <Form onSubmit={handleSubmit}>
      <FormTextField
        label="Name"
        value={form.name}
        onChange={v =>
          setForm(prev => ({
            ...prev,
            name: v,
          }))
        }
        placeholder="e.g. Email Signature"
        error={errors.name}
        autoFocus
      />
      <FormTextField
        label="Keyword"
        value={form.keyword}
        onChange={v =>
          setForm(prev => ({
            ...prev,
            keyword: v,
          }))
        }
        placeholder="e.g. !sig"
        description="Type this to expand the snippet"
      />
      <FormDropdown
        label="Category"
        value={form.category}

