import {
  type ReactNode,
  useCallback,
  useEffect,
  useMemo,
  useState,
} from 'react';
import { TAG_COLOR_HEX, type TagColor } from '../../constants/tag_colors';
import type { QuicklinkEntry, QuicklinkType } from '../../data/quicklinks_data';
import {
  MOCK_QUICKLINKS,
  QUICKLINK_TYPE_LABELS,
  getQuicklinkIcon,
} from '../../data/quicklinks_data';
import { useAlert } from '../../hooks/use_alert';
import { useHUD } from '../../hooks/use_hud';
import { useKeyboardShortcut } from '../../hooks/use_keyboard_shortcut';
import { useNavigation } from '../../hooks/use_navigation';
import { formatRelativeDate } from '../../utils/format_date';
import { fuzzyMatch } from '../../utils/fuzzy_search';
import { openUrl } from '../../utils/open_url';
import { isRecord, storageGet, storageSet } from '../../utils/storage';
import { ActionPanel } from '../action_panel/action_panel';
import {
  CopyHUDIcon,
  OpenInBrowserHUDIcon,
  createCopyAction,
  performCopy,
} from '../action_panel/actions';
import type { DropdownSection } from '../action_panel/actions_dropdown';
import { Alert } from '../alert/alert';
import { EmptyState } from '../empty_state/empty_state';
import { Form, FormDropdown, FormTextField } from '../form';
import { HUDContainer } from '../hud/hud_container';
import { Kbd } from '../kbd/kbd';
import { List, ListItem, ListSection } from '../list';
import { SearchBar } from '../search_bar/search_bar';
import type { SearchDropdownSection } from '../search_bar/search_dropdown';
import { SearchDropdown } from '../search_bar/search_dropdown';

function SearchEmptyIcon() {
  return (
    <svg width="48" height="48" viewBox="0 0 48 48" fill="none">
      <circle cx="21" cy="21" r="12" stroke="currentColor" strokeWidth="3" />
      <line
        x1="30"
        y1="30"
        x2="42"
        y2="42"
        stroke="currentColor"
        strokeWidth="3"
        strokeLinecap="round"
      />
    </svg>
  );
}

const QUICKLINKS_KEY = 'quicklinks';

interface StoredQuicklink {
  id: string;
  name: string;
  link: string;
  type: QuicklinkType;
  application?: string;
  tags?: { text: string; color?: string }[];
  createdAt: string;
}

function isStoredTag(value: unknown): value is { text: string; color?: string } {
  if (!isRecord(value)) return false;
  if (typeof value.text !== 'string') return false;
  if ('color' in value && typeof value.color !== 'string') return false;
  return true;
}

function isQuicklinkType(value: string): value is QuicklinkType {
  return value === 'url' || value === 'file' || value === 'deeplink';
}

function isStoredQuicklinkArray(value: unknown): value is StoredQuicklink[] {
  if (!Array.isArray(value)) return false;
  return value.every(
    v =>
      isRecord(v) &&
      typeof v.id === 'string' &&
      typeof v.name === 'string' &&
      typeof v.link === 'string' &&
      typeof v.type === 'string' &&
      typeof v.createdAt === 'string' &&
      (!v.tags || (Array.isArray(v.tags) && v.tags.every(isStoredTag))),
  );
}

const TAG_COLOR_NAMES = new Set<string>(Object.keys(TAG_COLOR_HEX));

function isTagColor(value: string): value is TagColor {
  return TAG_COLOR_NAMES.has(value);
}

function serializeEntries(entries: QuicklinkEntry[]): StoredQuicklink[] {
  return entries.map(e => ({
    id: e.id,
    name: e.name,
    link: e.link,
    type: e.type,
    application: e.application,
    tags: e.tags,
    createdAt: e.createdAt.toISOString(),
  }));
}

function deserializeEntries(stored: StoredQuicklink[]): QuicklinkEntry[] {
  return stored.map(s => {
    const parsed = new Date(s.createdAt);
    const createdAt = Number.isNaN(parsed.getTime()) ? new Date() : parsed;
    return {
      id: s.id,
      name: s.name,
      link: s.link,
      type: isQuicklinkType(s.type) ? s.type : 'url',
      application: s.application,
      icon: getQuicklinkIcon(isQuicklinkType(s.type) ? s.type : 'url'),
      tags: s.tags?.map(t => ({
        text: t.text,
        color: t.color && isTagColor(t.color) ? t.color : undefined,
      })),
      createdAt,
    };
  });
}

function loadQuicklinks(): QuicklinkEntry[] {
  const stored = storageGet(QUICKLINKS_KEY, isStoredQuicklinkArray);
  if (stored) return deserializeEntries(stored);
  return MOCK_QUICKLINKS;
}

function saveQuicklinks(entries: QuicklinkEntry[]) {
  storageSet(QUICKLINKS_KEY, serializeEntries(entries));
}

const FILTER_SECTIONS: SearchDropdownSection[] = [
  {
    options: [{ label: 'All', value: 'all' }],
  },
  {
    title: 'Type',
    options: [
      { label: 'URLs', value: 'url' },
      { label: 'File Paths', value: 'file' },
      { label: 'Deep Links', value: 'deeplink' },
    ],
  },
];

interface QuicklinkFormState {
  name: string;
  link: string;
  type: QuicklinkType;
  application: string;
}

const INITIAL_FORM: QuicklinkFormState = {
  name: '',
  link: '',
  type: 'url',
  application: '',
};

const TYPE_OPTIONS = [
  { label: 'URL', value: 'url' },
  { label: 'File Path', value: 'file' },
  { label: 'Deep Link', value: 'deeplink' },
];

interface EditQuicklinkViewProps {
  quicklink?: QuicklinkEntry;
  onSubmit: (form: QuicklinkFormState) => void;
}

function EditQuicklinkView({ quicklink, onSubmit }: EditQuicklinkViewProps) {
  const [form, setForm] = useState<QuicklinkFormState>(() => {
    if (quicklink) {
      return {
        name: quicklink.name,
        link: quicklink.link,
        type: quicklink.type,
        application: quicklink.application ?? '',
      };
    }
    return INITIAL_FORM;
  });
  const [errors, setErrors] = useState<Partial<Record<keyof QuicklinkFormState, string>>>({});

  const handleSubmit = useCallback(() => {
    const newErrors: Partial<Record<keyof QuicklinkFormState, string>> = {};
    if (!form.name.trim()) {
      newErrors.name = 'Name is required';
    }
    if (!form.link.trim()) {
      newErrors.link = 'Link is required';
    }
    setErrors(newErrors);
    if (Object.keys(newErrors).length > 0) return;
    onSubmit(form);
  }, [form, onSubmit]);

  useKeyboardShortcut({ key: 'Enter', meta: true }, handleSubmit);

  return (
    <Form onSubmit={handleSubmit}>
      <FormTextField
        label="Name"
        value={form.name}
        onChange={v => setForm(prev => ({ ...prev, name: v }))}
        placeholder="e.g. GitHub Dashboard"
        error={errors.name}
        autoFocus
      />
      <FormTextField
        label="Link"
        value={form.link}
        onChange={v => setForm(prev => ({ ...prev, link: v }))}
        placeholder="e.g. https://github.com or ~/Documents"
        description="Use {query} as placeholder for dynamic input"
        error={errors.link}
      />
      <FormDropdown
        label="Type"
        value={form.type}
        onChange={v => setForm(prev => ({ ...prev, type: v as QuicklinkType }))}
        options={TYPE_OPTIONS}
      />
      <FormTextField
        label="Open With"
        value={form.application}
        onChange={v => setForm(prev => ({ ...prev, application: v }))}
        placeholder="e.g. Safari (optional)"
        description="Application to open the link with"
      />
    </Form>
  );
}

export function QuicklinksView() {
