            stroke="currentColor"
            strokeWidth="1.5"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
        </svg>
      ),
      primaryAction: {
        label: 'Delete',
        style: 'destructive',
        onAction: () => {
          setEntries(prev => {
            const next = prev.filter(e => e.id !== entryId);
            saveQuicklinks(next);
            return next;
          });
          showHUD({
            icon: <CopyHUDIcon />,
            title: `Deleted "${entryName}"`,
          });
        },
      },
      dismissAction: {
        label: 'Cancel',
        style: 'cancel',
        onAction: () => {},
      },
    });
  }, [selectedEntry, confirmAlert, showHUD]);

  const handleFormSubmit = useCallback(
    (form: QuicklinkFormState) => {
      if (subView === 'edit' && editingEntry) {
        setEntries(prev => {
          const next = prev.map(e =>
            e.id === editingEntry.id
              ? {
                  ...e,
                  name: form.name.trim(),
                  link: form.link.trim(),
                  type: form.type,
                  application: form.application.trim() || undefined,
                }
              : e,
          );
          saveQuicklinks(next);
          return next;
        });
        showHUD({
          icon: <CopyHUDIcon />,
          title: `Updated "${form.name.trim()}"`,
        });
      } else {
        const newEntry: QuicklinkEntry = {
          id: crypto.randomUUID(),
          name: form.name.trim(),
          link: form.link.trim(),
          type: form.type,
          application: form.application.trim() || undefined,
          createdAt: new Date(),
        };
        setEntries(prev => {
          const next = [newEntry, ...prev];
          saveQuicklinks(next);
          return next;
        });
        showHUD({
          icon: <CopyHUDIcon />,
          title: `Created "${form.name.trim()}"`,
        });
      }
      setSubView('list');
      setEditingEntry(undefined);
    },
    [subView, editingEntry, showHUD],
  );

  const handleAction = useCallback(() => {
    handleOpen();
  }, [handleOpen]);

  const toggleActions = useCallback(() => {
    setActionsOpen(prev => !prev);
  }, []);

  const closeActions = useCallback(() => {
    setActionsOpen(false);
  }, []);

  useKeyboardShortcut({ key: 'k', meta: true }, toggleActions, {
    enabled: subView === 'list',
  });
  useKeyboardShortcut({ key: 'c', meta: true }, handleCopyLink, {
    enabled: subView === 'list',
  });
  useKeyboardShortcut({ key: 'e', meta: true }, handleEdit, {
    enabled: subView === 'list',
  });
  useKeyboardShortcut({ key: 'n', meta: true }, handleCreate, {
    enabled: subView === 'list',
  });
  useKeyboardShortcut({ key: 'Backspace', meta: true }, handleDelete, {
    enabled: subView === 'list',
  });

  const dropdownSections: DropdownSection[] = useMemo(
    () => [
      {
        title: 'Actions',
        actions: [
          {
            label: 'Open',
            shortcut: <Kbd keys={['↵']} />,
            onClick: handleOpen,
          },
          {
            label: 'Edit',
            shortcut: <Kbd keys={['⌘', 'E']} />,
            onClick: handleEdit,
          },
          createCopyAction(
            {
              content: selectedEntry?.link ?? '',
              title: 'Copy Link',
              shortcut: <Kbd keys={['⌘', 'C']} />,
              hudTitle: 'Link Copied',
            },
            showHUD,
          ),
          {
            label: 'Create Quicklink',
            shortcut: <Kbd keys={['⌘', 'N']} />,
            onClick: handleCreate,
          },
        ],
      },
      {
        title: 'Danger Zone',
        actions: [
          {
            label: 'Delete',
            shortcut: <Kbd keys={['⌘', '⌫']} />,
            onClick: handleDelete,
          },
        ],
      },
    ],
    [selectedEntry?.link, handleOpen, handleEdit, handleCreate, handleDelete, showHUD],
  );

  const activeDescendantId =
    totalItemCount > 0 ? `list-item-${selectedIndex}` : undefined;

  const handleEscape = useCallback(() => {
    if (subView !== 'list') {
      setSubView('list');
      setEditingEntry(undefined);
    }
  }, [subView]);

  useKeyboardShortcut({ key: 'Escape' }, handleEscape, {
    enabled: subView !== 'list',
  });

  if (subView === 'edit' || subView === 'create') {
    const formTitle = subView === 'edit' ? 'Edit Quicklink' : 'Create Quicklink';
    return (
      <>
        <SearchBar
          value=""
          onChange={() => {}}
          placeholder={formTitle}
          breadcrumbs={[
            ...(nav.breadcrumbs.length > 0 ? nav.breadcrumbs : []),
            {
              label: formTitle,
              onBack: () => {
                setSubView('list');
                setEditingEntry(undefined);
              },
            },
          ]}
        />
        <div className="command-palette__body">
          <div className="command-palette__list-container">
            <EditQuicklinkView
              quicklink={subView === 'edit' ? editingEntry : undefined}
              onSubmit={handleFormSubmit}
            />
          </div>
        </div>
        <ActionPanel
          contextLabel="Quicklinks"
          actions={[
            {
              label: subView === 'edit' ? 'Save' : 'Create',
              shortcut: <Kbd keys={['⌘', '↵']} />,
            },
          ]}
        />
        <HUDContainer items={hudItems} />
      </>
    );
  }

  function renderQuicklinkItem(entry: QuicklinkEntry, idx: number): ReactNode {
    const accessories = [
      ...(entry.tags?.map(t => ({ tag: t })) ?? []),
      { text: QUICKLINK_TYPE_LABELS[entry.type] },
      {
        text: formatRelativeDate(entry.createdAt, now),
        tooltip: entry.createdAt.toLocaleString(),
      },
    ];
    if (entry.application) {
      accessories.unshift({ text: entry.application });
    }

    return (
      <ListItem
        key={entry.id}
        index={idx}
        icon={entry.icon ?? getQuicklinkIcon(entry.type)}
        title={entry.name}
        subtitle={entry.link}
        accessories={accessories}
        query={query || undefined}
      />
    );
  }

  return (
    <>
      <SearchBar
        value={query}
        onChange={handleQueryChange}
        placeholder="Search Quicklinks..."
        activeDescendantId={activeDescendantId}
        breadcrumbs={nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined}
        dropdown={
          <SearchDropdown
            sections={FILTER_SECTIONS}
            value={filterValue}
            onChange={handleFilterChange}
          />
        }
      />
      <div className="command-palette__body">
        <div className="command-palette__list-container">
          {totalItemCount === 0 ? (
            <EmptyState
              icon={<SearchEmptyIcon />}
              title="No Quicklinks"
              description="Try a different search or create a new quicklink"
            />
          ) : (
            <List
              itemCount={totalItemCount}
              onActiveIndexChange={handleActiveIndexChange}
              onAction={handleAction}
            >
              {(() => {
                let globalIndex = 0;
                const sections: ReactNode[] = [];

                if (urlItems.length > 0) {
                  sections.push(
                    <ListSection key="urls" title="URLs">
                      {urlItems.map(entry =>
                        renderQuicklinkItem(entry, globalIndex++),
                      )}
                    </ListSection>,
                  );
                }

                if (fileItems.length > 0) {
                  sections.push(
                    <ListSection key="files" title="File Paths">
                      {fileItems.map(entry =>
                        renderQuicklinkItem(entry, globalIndex++),
                      )}
                    </ListSection>,
                  );
                }

                if (deeplinkItems.length > 0) {
                  sections.push(
                    <ListSection key="deeplinks" title="Deep Links">
                      {deeplinkItems.map(entry =>
                        renderQuicklinkItem(entry, globalIndex++),
                      )}
                    </ListSection>,
                  );
                }

                return sections;
              })()}
            </List>
          )}
        </div>
      </div>
      <ActionPanel
        contextLabel="Quicklinks"
        actions={[
          {
            label: 'Open',
            shortcut: <Kbd keys={['↵']} />,
          },
          {
            label: 'Actions',
            shortcut: <Kbd keys={['⌘', 'K']} />,
            onClick: toggleActions,
          },
        ]}
        dropdownOpen={actionsOpen}
        dropdownSections={dropdownSections}
        onDropdownClose={closeActions}
      />
      {alertState && (
        <Alert
          title={alertState.title}
          message={alertState.message}
          icon={alertState.icon}
          primaryAction={alertState.primaryAction}
          dismissAction={alertState.dismissAction}
          onDismiss={dismissAlert}
        />
      )}
      <HUDContainer items={hudItems} />
    </>
  );
}

