 58→const QUICKLINKS_KEY = 'quicklinks';
 59→
 60→interface StoredQuicklink {
 61→  id: string;
 62→  name: string;
 63→  link: string;
 64→  type: QuicklinkType;
 65→  application?: string;
 66→  tags?: {
 67→    text: string;
 68→    color?: string;
 69→  }[];
 70→  createdAt: string;
 71→}
 72→
 73→function isStoredTag(value: unknown): value is {
 74→  text: string;
 75→  color?: string;
 76→} {
 77→  if (!isRecord(value)) return false;
 78→  if (typeof value.text !== 'string') return false;
 79→  if (
 80→  'color' in value &&
 81→  typeof value.color !== 'string'
 82→  ) {
 83→    return false;
 84→  }
 85→  return true;
 86→}
 87→
 88→function isQuicklinkType(value: string): value is QuicklinkType {
 89→  return value === 'url' || value === 'file' || value === 'deeplink';
 90→}
 91→
 92→function isStoredQuicklinkArray(value: unknown): value is StoredQuicklink[] {
 93→  if (!Array.isArray(value)) return false;
 94→  return value.every(
 95→    v =>
 96→      isRecord(v) &&
 97→      typeof v.id === 'string' &&
 98→      typeof v.name === 'string' &&
 99→      typeof v.link === 'string' &&
100→      typeof v.type === 'string' &&
101→      typeof v.createdAt === 'string' &&
102→      (!v.tags || (Array.isArray(v.tags) && v.tags.every(isStoredTag))),
103→  );
104→}
105→
106→const TAG_COLOR_NAMES = new Set<string>(Object.keys(TAG_COLOR_HEX));
107→
108→function isTagColor(value: string): value is TagColor {
109→  return TAG_COLOR_NAMES.has(value);
110→}
111→
112→function serializeEntries(entries: QuicklinkEntry[]): StoredQuicklink[] {
113→  return entries.map(e => ({
114→    id: e.id,
115→    name: e.name,
116→    link: e.link,
117→    type: e.type,
118→    application: e.application,
119→    tags: e.tags,
120→    createdAt: e.createdAt.toISOString(),
121→  }));
122→}
123→
124→function deserializeEntries(stored: StoredQuicklink[]): QuicklinkEntry[] {
125→  return stored.map(s => {
126→    const parsed = new Date(s.createdAt);
127→    const createdAt = Number.isNaN(parsed.getTime()) ? new Date() : parsed;
128→    return {
129→      id: s.id,
130→      name: s.name,
131→      link: s.link,
132→      type: isQuicklinkType(s.type) ? s.type : 'url',
133→      application: s.application,
134→      icon: getQuicklinkIcon(isQuicklinkType(s.type) ? s.type : 'url'),
135→      tags: s.tags?.map(t => ({
136→        text: t.text,
137→        color: t.color && isTagColor(t.color) ? t.color : undefined,
138→      })),
139→      createdAt,
140→    };
141→  });
142→}
143→
144→function loadQuicklinks(): QuicklinkEntry[] {
145→  const stored = storageGet(QUICKLINKS_KEY, isStoredQuicklinkArray);
146→  if (stored) return deserializeEntries(stored);
147→  return MOCK_QUICKLINKS;
148→}
149→
150→function saveQuicklinks(entries: QuicklinkEntry[]) {
151→  storageSet(QUICKLINKS_KEY, serializeEntries(entries));
152→}
